import{_ as e,o as d,c as r,ae as l}from"./chunks/framework.DD8idMxO.js";const g=JSON.parse('{"title":"Skill 生成（Generation）","description":"","frontmatter":{},"headers":[],"relativePath":"radar/category-01-generation.md","filePath":"radar/category-01-generation.md"}'),a={name:"radar/category-01-generation.md"};function o(n,t,i,h,s,c){return d(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="skill-生成-generation" tabindex="-1">Skill 生成（Generation） <a class="header-anchor" href="#skill-生成-generation" aria-label="Permalink to &quot;Skill 生成（Generation）&quot;">​</a></h1><blockquote><p><strong>成熟度</strong>: 🟡 成长期 · <strong>综合评分</strong>: <strong>0.55</strong></p><p><strong>业界判断</strong>：9 个产品占据<strong>最拥挤</strong>的赛道（失败驱动 / 文档转化 / 会话提取 / 轨迹蒸馏 / 领域工单 / RL 共进化 / GEPA 进化），每条路径都局限于特定输入类型，差异化空间正在缩小。</p></blockquote><hr><h2 id="业界代表产品" tabindex="-1">业界代表产品 <a class="header-anchor" href="#业界代表产品" aria-label="Permalink to &quot;业界代表产品&quot;">​</a></h2><table tabindex="0"><thead><tr><th>产品</th><th>来源</th><th>核心路径</th><th>关键数字</th></tr></thead><tbody><tr><td><a href="./tech-skill-creator.html">Skill Creator</a></td><td>Anthropic 官方</td><td>引导式 + Eval 闭环</td><td>基线通过率 34.1%</td></tr><tr><td><a href="./tech-skill-seekers.html">Skill Seekers</a></td><td>社区 (13.4K+ ★)</td><td>18 源 → 20 目标</td><td>AI 增强 3/10 → 9/10</td></tr><tr><td><a href="./tech-evoskill.html">EvoSkill</a></td><td>Sentient AGI (726 ★)</td><td>三 Agent 失败驱动</td><td><strong>+7.3% OfficeQA / +12.1% SealQA</strong></td></tr><tr><td><a href="./tech-evoskills.html">EvoSkills / CoEvoSkills</a></td><td>学术</td><td>Surrogate + Oracle 协同进化</td><td><strong>75% vs 人工 34.1%</strong></td></tr><tr><td><a href="./tech-claudeception.html">Claudeception</a></td><td>社区 (<strong>2.3K+ ★</strong>)</td><td>Claude Code 会话提取</td><td>4 条件提取标准</td></tr><tr><td><a href="./tech-trace2skill.html">Trace2Skill</a></td><td>阿里 Qwen + ETH</td><td>并行轨迹蒸馏</td><td>35B +57.65pp 超 122B</td></tr><tr><td><a href="./tech-skillforge.html">SkillForge</a></td><td>工业研究 (SIGIR 2026)</td><td>历史工单挖掘</td><td><strong>1,883 工单 + 5 真实场景</strong></td></tr><tr><td><a href="./tech-skillx.html">SkillX</a></td><td>学术</td><td>三层粒度蒸馏</td><td>强模型 → 弱模型</td></tr><tr><td><a href="./tech-skillrl.html">SkillRL</a></td><td>aiming-lab</td><td>经验蒸馏 + RL 共进化</td><td><strong>+15.3% ALFWorld / WebShop</strong></td></tr></tbody></table><hr><h2 id="七大数据源覆盖" tabindex="-1">七大数据源覆盖 <a class="header-anchor" href="#七大数据源覆盖" aria-label="Permalink to &quot;七大数据源覆盖&quot;">​</a></h2><table tabindex="0"><thead><tr><th>数据源</th><th style="text-align:center;">业界覆盖</th><th>代表产品</th></tr></thead><tbody><tr><td>问题单 / 工单</td><td style="text-align:center;">✅</td><td>SkillForge</td></tr><tr><td>网页链接 / 在线文档</td><td style="text-align:center;">✅</td><td>Skill Seekers</td></tr><tr><td>代码仓 / 项目文档</td><td style="text-align:center;">✅</td><td>Skill Seekers / OpenSpace</td></tr><tr><td>Agent 执行轨迹</td><td style="text-align:center;">✅</td><td>Trace2Skill / EvoSkill / OpenSpace</td></tr><tr><td>会话历史</td><td style="text-align:center;">✅</td><td>Claudeception / Hermes</td></tr><tr><td>已有的其他 Skill</td><td style="text-align:center;">✅</td><td>SkillX / OpenSpace（DERIVED）</td></tr><tr><td>内部文档（含工具引用）</td><td style="text-align:center;">✅</td><td>SkillForge</td></tr><tr><td>内部文档（含图片 / 流程图）</td><td style="text-align:center;">❌</td><td>—</td></tr><tr><td>代码检视记录 / PR / Issue</td><td style="text-align:center;">❌</td><td>—</td></tr><tr><td>测试用例 / 测试日志</td><td style="text-align:center;">❌</td><td>—</td></tr><tr><td>零碎代码片段 / 脚本</td><td style="text-align:center;">❌</td><td>—</td></tr></tbody></table><hr><h2 id="行业痛点" tabindex="-1">行业痛点 <a class="header-anchor" href="#行业痛点" aria-label="Permalink to &quot;行业痛点&quot;">​</a></h2><h3 id="🟡-自动化生产规模化" tabindex="-1">🟡 自动化生产规模化 <a class="header-anchor" href="#🟡-自动化生产规模化" aria-label="Permalink to &quot;🟡 自动化生产规模化&quot;">​</a></h3><p>每写一个 Skill 要数小时，团队覆盖几十个场景忙不过来。当前 7+ 条自动化路径<strong>各有侧重但都局限于特定输入类型</strong>。</p><h3 id="🟡-经验跨会话丢失" tabindex="-1">🟡 经验跨会话丢失 <a class="header-anchor" href="#🟡-经验跨会话丢失" aria-label="Permalink to &quot;🟡 经验跨会话丢失&quot;">​</a></h3><p>上周 Agent 解决了一个棘手 Bug，这周遇到类似问题又从零开始 —— Agent 每天&quot;失忆&quot;。Claudeception / SkillNet / OpenSpace / SkillClaw / Hermes 都在解决，但<strong>跨项目、跨团队、跨 Agent 平台的迁移仍受限</strong>。</p><h3 id="🟡-skill-关系管理空白" tabindex="-1">🟡 Skill 关系管理空白 <a class="header-anchor" href="#🟡-skill-关系管理空白" aria-label="Permalink to &quot;🟡 Skill 关系管理空白&quot;">​</a></h3><p>Skill 库里 30 个 Skill 做类似的事，不知道用哪个，也不敢删。SkillNet Ontology 是初步方案，但<strong>动态组合和跨领域迁移仍具挑战性</strong>。</p><h3 id="🟡-单次生成质量不稳" tabindex="-1">🟡 单次生成质量不稳 <a class="header-anchor" href="#🟡-单次生成质量不稳" aria-label="Permalink to &quot;🟡 单次生成质量不稳&quot;">​</a></h3><p>让 Agent 自己写 Skill 质量时好时坏。EvoSkills 迭代 5 轮通过率 75% —— 仍有 25% 失败。</p><h3 id="🟡-人机认知失配" tabindex="-1">🟡 人机认知失配 <a class="header-anchor" href="#🟡-人机认知失配" aria-label="Permalink to &quot;🟡 人机认知失配&quot;">​</a></h3><p>人写给 LLM 的 Skill 很大一部分<strong>不是在&quot;帮&quot;LLM 而是在&quot;绊&quot;LLM</strong>。EvoSkills 让 LLM 自己进化 Skill (75% vs 人工 34.1%)，但<strong>自进化 Skill 可解释性较差</strong>。</p><hr><h2 id="主流方法对比" tabindex="-1">主流方法对比 <a class="header-anchor" href="#主流方法对比" aria-label="Permalink to &quot;主流方法对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方法</th><th>信号源</th><th>优势</th><th>局限</th></tr></thead><tbody><tr><td>失败轨迹分析</td><td>EvoSkill / SkillForge 的执行失败</td><td>直接针对痛点</td><td>依赖 ground-truth</td></tr><tr><td>协同进化验证</td><td>EvoSkills 的 Surrogate Verifier</td><td>不完全依赖 ground-truth</td><td>LLM 自身知识有上限</td></tr><tr><td>并行轨迹池蒸馏</td><td>Trace2Skill</td><td>整体分析避免过拟合</td><td>冷启动受限</td></tr><tr><td>会话提取</td><td>Claudeception</td><td>隐性知识自动捕获</td><td>提取质量依赖 LLM 判断</td></tr><tr><td>文档转化</td><td>Skill Seekers</td><td>多源多平台</td><td>仅处理已有文档</td></tr><tr><td>领域工单挖掘</td><td>SkillForge</td><td>工业场景验证</td><td>仅限工单数据</td></tr><tr><td>RL 共进化</td><td>SkillRL</td><td>Skill 库随策略一起学习</td><td>需要可定义 reward</td></tr></tbody></table>',23)])])}const S=e(a,[["render",o]]);export{g as __pageData,S as default};
